"""AGENTS.md Auto-Generation Utilities

Provides automatic generation and updating of AGENTS.md files,
inspired by oh-my-codex's agents-md.ts.
"""

from dataclasses import dataclass
from pathlib import Path

# Marker for auto-generated content
OMX_GENERATED_AGENTS_MARKER = "<!-- omx:generated:agents-md -->"
OMX_GENERATED_AGENTS_TITLE = "## Auto-Generated Agent Config"


@dataclass
class AgentDefinition:
    """Represents an agent definition from AGENTS.md."""
    name: str
    description: str
    prompt_template: str
    tools: list[str]


def is_omx_generated_agents_md(content: str) -> bool:
    """Check if AGENTS.md content was auto-generated by OMX.
    
    Args:
        content: AGENTS.md file content
        
    Returns:
        True if content is auto-generated
    """
    return OMX_GENERATED_AGENTS_MARKER in content


def add_generated_agents_marker(content: str) -> str:
    """Add the auto-generated marker to content if not present.
    
    Args:
        content: AGENTS.md content
        
    Returns:
        Content with marker added
    """
    if OMX_GENERATED_AGENTS_MARKER in content:
        return content

    return f"{content}\n\n{OMX_GENERATED_AGENTS_MARKER}\n"


def parse_agents_md(content: str) -> list[AgentDefinition]:
    """Parse AGENTS.md into agent definitions.
    
    Args:
        content: AGENTS.md file content
        
    Returns:
        List of AgentDefinition objects
    """
    agents = []

    # Split by ## headings
    current_agent = None

    for line in content.split("\n"):
        if line.startswith("## "):
            # Save previous
            if current_agent:
                agents.append(current_agent)

            name = line[3:].strip()
            current_agent = AgentDefinition(
                name=name,
                description="",
                prompt_template="",
                tools=[],
            )
        elif current_agent:
            if line.startswith("**Description:**"):
                current_agent.description = line[14:].strip()
            elif line.startswith("**Prompt:**"):
                current_agent.prompt_template = line[10:].strip()
            elif line.startswith("**Tools:**"):
                # Tools follow on subsequent lines
                pass

    # Add last
    if current_agent:
        agents.append(current_agent)

    return agents


def format_agent_md(agent: AgentDefinition) -> str:
    """Format an agent definition as markdown.
    
    Args:
        agent: Agent definition
        
    Returns:
        Markdown formatted agent
    """
    lines = [
        f"## {agent.name}",
        "",
        f"**Description:** {agent.description}",
        "",
    ]

    if agent.prompt_template:
        lines.append(f"**Prompt:** {agent.prompt_template}")
        lines.append("")

    if agent.tools:
        lines.append("**Tools:**")
        for tool in agent.tools:
            lines.append(f"- {tool}")
        lines.append("")

    return "\n".join(lines)


def build_agents_md(
    agents: list[AgentDefinition],
    include_marker: bool = True,
) -> str:
    """Build AGENTS.md content from agent definitions.
    
    Args:
        agents: List of agent definitions
        include_marker: Whether to include auto-generated marker
        
    Returns:
        Complete AGENTS.md content
    """
    lines = [
        "# AGENTS.md",
        "",
        "This file provides guidance to AI coding agents when working with code in this repository.",
        "",
    ]

    if include_marker:
        lines.append(OMX_GENERATED_AGENTS_TITLE)
        lines.append("")

    # Add agents
    for agent in agents:
        lines.append(format_agent_md(agent))

    return "\n".join(lines)


def upsert_agents_md(
    content: str,
    agents: list[AgentDefinition],
    marker: str = OMX_GENERATED_AGENTS_MARKER,
) -> str:
    """Update or insert agent definitions in AGENTS.md.
    
    Args:
        content: Existing AGENTS.md content
        agents: Agent definitions to upsert
        marker: Auto-generated marker to use
        
    Returns:
        Updated AGENTS.md content
    """
    # Check if there's an existing auto-generated section
    if marker in content:
        # Split at marker
        parts = content.split(marker)
        if len(parts) == 2:
            return parts[0] + marker + "\n" + build_agents_md(agents, include_marker=False)

    # No existing section, append
    return content + "\n\n" + marker + "\n" + build_agents_md(agents, include_marker=False)


def read_agents_md(path: str) -> str | None:
    """Read AGENTS.md file content.
    
    Args:
        path: Path to AGENTS.md
        
    Returns:
        File content or None if not found
    """
    agents_path = Path(path)
    if not agents_path.exists():
        return None

    return agents_path.read_text(encoding="utf-8")


def write_agents_md(path: str, content: str) -> None:
    """Write AGENTS.md file.
    
    Args:
        path: Path to AGENTS.md
        content: Content to write
    """
    Path(path).write_text(content, encoding="utf-8")


def ensure_agents_md(
    project_root: str,
    agents: list[AgentDefinition] | None = None,
    force: bool = False,
) -> bool:
    """Ensure AGENTS.md exists and is up to date.
    
    Args:
        project_root: Project root directory
        agents: Agent definitions to include
        force: Whether to regenerate even if exists
        
    Returns:
        True if file was created/updated, False if skipped
    """
    agents_path = Path(project_root) / "AGENTS.md"

    if agents_path.exists() and not force:
        return False

    # Generate default content
    default_agents = agents or get_default_agents()
    content = build_agents_md(default_agents)

    write_agents_md(str(agents_path), content)
    return True


def get_default_agents() -> list[AgentDefinition]:
    """Get default agent definitions.
    
    Returns:
        List of default agent definitions
    """
    return [
        AgentDefinition(
            name="Coder",
            description="Primary code implementation agent",
            prompt_template="Implement the following feature: {task}",
            tools=["read_file", "write_to_file", "apply_diff"],
        ),
        AgentDefinition(
            name="Reviewer",
            description="Code review and quality assurance",
            prompt_template="Review the following code changes: {changes}",
            tools=["search_files", "read_file"],
        ),
        AgentDefinition(
            name="Architect",
            description="Architecture design and technical decisions",
            prompt_template="Design architecture for: {feature}",
            tools=["read_file", "search_files"],
        ),
    ]


# Legacy function names
def generate_agents_md(agents: list[AgentDefinition]) -> str:
    """Legacy alias for build_agents_md."""
    return build_agents_md(agents)


def update_agents_md(path: str, agents: list[AgentDefinition]) -> bool:
    """Legacy alias for ensure_agents_md."""
    project_root = str(Path(path).parent)
    return ensure_agents_md(project_root, agents, force=True)
